const PELICULAS: UnifiedMedia[] = [

  { id: 'aventura-extraordinaria-2012', title: 'Una aventura extraordinaria (2012)', source: 'embed', url: 'https://barmonrey.com/player/al4S2JY8DRmf0Yf/', thumbnail: 'https://sun9-53.userapi.com/impg/H4ghOoHscesK5nWLani7IcW_xmLLOfm4eagsuw/9ynd_Nb5VRc.jpg?size=300x450&quality=95&sign=cb572f4eef9f887f7063494f462c1f6e&type=album', description: 'Cuenta la historia de Santosh y Gita Patel, quienes dejan su vida en la India y viajan en un barco camino a Canadá junto a sus hijos y algunos animales, los cuales serán vendidos en ese país, luego de que tuvieran que vender un zoológico de su propiedad en la India porque el gobierno ya no los estaba apoyando. Después de días de viaje, una gran tormenta hunde el barco. El joven Pi, uno de los hijos de los Patel, es el único sobreviviente. Ahora se encuentra en un bote salvavidas en medio de la nada. Pero no está solo: Richard Parker, el tigre de bengala que viajaba con los Patel, se encuentra también en la pequeña nave. Los días pasan sobre el vasto océano y no se ve una esperanza de encontrar tierra pronto. Pi y el enorme tigre iniciarán un épico viaje donde deberán aprender a confiar el uno del otro para poder sobrevivir.', category: 'pelicula', tags: ['aventura', 'extraordinaria', 'drama', 'misterio', 'supervivencia'], author: 'Pelis182', duration: '' },
  { id: 'esquema-fenicio-2025', title: 'El esquema fenicio (2025)', source: 'embed', url: 'https://barmonrey.com/player/Key2PFngbEu7bKZ/', thumbnail: 'https://sun9-4.userapi.com/s/v1/ig2/C1inY0h93MUBB-3SzIDEiz2-7WRyDyTwtBj3MfW9tMQXJhFxwBYE4SYeB1gjQ2MU_lNZEpBjGEsn_C9Sc7G16TNJ.jpg?quality=95&as=32x48,48x72,72x108,108x162,160x240,240x360,300x450&from=bu&cs=300x0', description: 'El acaudalado empresario Zsa-zsa Korda nombra a su única hija, una monja, heredera de sus bienes. Al embarcarse en una nueva aventura, Korda pronto se convierte en el blanco de magnates conspiradores, terroristas extranjeros y asesinos decididos.', category: 'pelicula', tags: ['esquema', 'fenicio', 'acción', 'comedia', 'drama', 'thriller'], author: 'Pelis182', duration: '' },
  { id: 'teoria-del-caos-2008', title: 'La teoría del caos (2008)', source: 'embed', url: 'https://barmonrey.com/player/GE979I7IL1yMnP4/', thumbnail: 'https://sun9-82.userapi.com/s/v1/ig2/D6o1aWUKZCp_X3IdXRfayl1cJ7gydEYUCXlJhhQRbJOjPOtx-qiBpAcqJxF5NlNmCO9-Y9lr3WD2mYmTMX9Cy47o.jpg?quality=95&as=32x48,48x72,72x108,108x162,160x240,240x360,300x450&from=bu&cs=300x0', description: 'La historia gira entorno a Frank Allen, un especialista en ser perfecto. Su vida va cronometrada: tiene que llegar a tiempo al ferry que le lleva a su trabajo, debe llegar a tiempo al trabajo, y, por encima de todo, tiene que ser feliz en su matrimonio. Pero, a pesar de sus intentos, todo comienza a desmoronarse y su vida se descontrola, dejando la monotonía de manera radical.', category: 'pelicula', tags: ['teoría', 'caos', 'comedia', 'drama', 'romance'], author: 'Pelis182', duration: '' },
  { id: 'frankenstein-2025', title: 'Frankenstein (2025)', source: 'embed', url: 'https://barmonrey.com/player/2v8blEHLwfXuxEm/', thumbnail: 'https://sun9-22.userapi.com/s/v1/ig2/MigbnlpJZzHShcYnGRd2CJoNvbt9SqScVv0J28qqvUtMNRc_1wouGB9Bt8xiU91kUYHiqUSCJYiIc7H36_ZsFBfr.jpg?quality=95&as=32x48,48x72,72x108,108x162,160x240,240x360,300x450&from=bu&cs=300x0', description: 'Adaptación cinematográfica de la novela escrita por Mary Shelley en el año 1818. La historia universal cuenta cómo la obsesión de un doctor por revivir a los muertos y darles la vida de manera científica hace que, sorpresivamente, «nazca» el monstruo Frankenstein. Después de indagar y emplear su valioso tiempo en documentarse y estudiar si su plan podría tener buenos resultados, sabe que debe adquirir miembros del cuerpo de muertos. Con la forma de humano ya en su mesa de laboratorio y un rayo eléctrico, el doctor Viktor Frankenstein consegue el éxito que esperaba: un ser creado a partir de partes de cadáveres que tendrá que lidar con la vuelta a la vida y vagar sin saber quién es ni cuál es su identidad. Siendo marginado por la sociedad por su apariencia.', category: 'pelicula', tags: ['frankenstein', 'terror', 'drama', 'ficción', 'monstruo', 'mary shelley'], author: 'Pelis182', duration: '' },
  { id: 'mira-como-corren-2022', title: 'Mira cómo corren (2022)', source: 'embed', url: 'https://barmonrey.com/player/awB8GxvyF17YUmW/', thumbnail: 'https://sun9-14.userapi.com/impg/gC3WwK0hie91JbZgudvYybSv8w6WZRoNjh3Jiw/KtHGZWSwqog.jpg?size=300x450&quality=95&sign=72ccdd0d67039fc195ed3caa8d61fb1e&type=album', description: 'Ambientada en el West End del Londres de los años 50, los planes para una versión cinematográfica de una exitosa obra de teatro se ven interrumpidos bruscamente tras el asesinato de un director de cine de Hollywood. Cuando el inspector Stoppard y la entusiasta recién llegada agente Stalker se hacen cargo del caso, ambos se ven envueltos en un intrigante misterio dentro del glamuroso y decadente teatro clandestino, investigando el crimen por su cuenta y riesgo.', category: 'pelicula', tags: ['mira', 'corren', 'comedia', 'misterio', 'thriller'], author: 'Pelis182', duration: '' },
  { id: 'peso-del-talento-2022', title: 'El peso del talento (2022)', source: 'embed', url: 'https://barmonrey.com/player/gf9kH4r8CcI33Rk/', thumbnail: 'https://sun9-16.userapi.com/s/v1/if2/HBmU_B2tHDdMem3tZ7Sxepyr97urx8XO_12Gtmvjmo5fuHb4r-yqDwYMw8_5wWuB3XGtwvBw18wIdx16env55vE8.jpg?size=300x450&quality=95&type=album', description: 'Frustrado creativamente y con problemas de dinero, Nicolas Cage decide aceptar un millón de dólares, a cambio de assister a la fiesta de cumpleaños de un súper fan que dice ser el más fan de todos los fans: Javi. Sin embargo, las cosas dan un giro inesperado cuando Cage es reclutado por la CIA, ya que el fan multimillonario es un capo de la droga y fue elegido para una película de Tarantino. Obligándolo a reencarnar sus personajes más icónicos y amados, con tal de salvarse a sí mismo y a los suyos de este complicado enredo.', category: 'pelicula', tags: ['peso', 'talento', 'nicolas cage', 'acción', 'comedia'], author: 'Pelis182', duration: '' },
  { id: 'lobo-wall-street-2013', title: 'El lobo de Wall Street (2013)', source: 'embed', url: 'https://barmonrey.com/player/OEvwHyF6GGFXvTS/', thumbnail: 'https://sun9-17.userapi.com/impg/HfJJCTPJk5uFnkoXkiSrjFyRH_r6VtWjJkc4xw/otX7I8omybo.jpg?size=300x450&quality=95&sign=92ddbe1ff81c514375e04b4f47bc841c&type=album', description: 'Jordan Belfort es muy joven, apenas tiene 24 años, pero también es muy ambicioso. Su afán por hacer dinero le lleva a convertirse en un bróker destacado de Wall Street y directivo de la empresa de inversiones bursátiles Stratton Oakmont, disposto a todo para enriquecerse. Corren los años 90 y en el parqué de Nueva York casi todo vale. A costa de traficar con bonos basura y de estafar a numerosos inversores, Belfort se convierte pronto en una máquina de hacer dinero, y también de gastarlo. En un día podrá engordar sus cuentas con millones de dólares y gastarlos por la noche a la misma velocidad. El juego sucio que lleva en la bolsa lo aplica también en su vida extra profesional.', category: 'pelicula', tags: ['lobo', 'wall street', 'drama', 'comedia', 'crimen'], author: 'Pelis182', duration: '180 min' },
  { id: 'battle-angel-2019', title: 'Battle Angel: La última guerrera (2019)', source: 'embed', url: 'https://barmonrey.com/player/xCMv1IxXuqHh6RP/', thumbnail: 'https://sun9-46.userapi.com/s/v1/ig2/Q11D6d3sK7k.jpg?quality=95&as=32x48,48x72,72x108,108x162,160x240,240x360,300x450&from=bu&cs=300x0', description: 'Siglo XXVI. Alita es una cyborg semi-humana a la que rescata de entre la chatarra el Doctor Dyson Ido, un científico que la reconstruye y la adopta como su hija. A medida que pasa el tiempo, queda patente que Alita posee unas habilidades de combate tan grandes como misteriosas. Incapaz de recordar su propio pasado, la joven cyborg se pondrá a prueba frente a situaciones que hagan florecer estas habilidades, de forma que pueda obtener respuestas sobre su origen. Seará así una aventura por descubrir la verdad sobre quién es en una lucha para cambiar el mundo.', category: 'pelicula', tags: ['batlle angel', 'acción', 'aventura', 'ciencia ficción'], author: 'Pelis182', duration: '' },
  {
  id: 'super-mario-galaxy-2026',
  title: 'Super Mario Galaxy: La película (2026)',
  source: 'youtube',
  url: 'https://ok.ru/videoembed/13653332003505?nochat=1',
  thumbnail: 'https://sun9-55.userapi.com/s/v1/ig2/6m2bOyr7H919ovfBDeaIgvZAHHZO9YdoeH2Up71gD5PDMUQxl9uktr7hwvPNqV2mtVUQ3rs4klxohhaVWfNiXlft.jpg?quality=95&as=32x48,48x72,72x108,108x162,160x240,240x360,300x450&from=bu&u=DTgKkzaMNY2yhxrbFJ7N0kM6qjAkMmiGjlSTMaij9Vg&cs=300x0',
  description: 'Mario y Luigi, los hermanos plomeros, se dedican a resolver todo tipo de problemas cotidianos en su nuevo hogar, el Reino Champiñón, con su habitual actitud positiva. Mientras ayudan a la princesa Peach e intentan reformar a un diminuto Bowser que está encarcelado, conocen a un nuevo compañero: Yoshi. Sin embargo, la fiesta de cumpleaños de la princesa Peach desencadena una aventura galáctica que envía a Mario y Luigi al espacio para detener los malvados planes de Bowser Jr. y salvar a Rosalina.',
  category: 'pelicula',
  tags: ['super mario', 'galaxy', 'animación', 'aventura', 'fantasía', 'nintendo'],
  author: 'Nintendo',
  duration: '90 min'
  },

  { id: 'castillo-vagabundo-2004', title: 'El incredible castillo vagabundo (2004)', source: 'embed', url: 'https://barmonrey.com/player/nK893RmVa7kSVEn/', thumbnail: 'https://sun9-5.userapi.com/impg/VVvgKAw8-6BrQe_Rw6kCFNVE3fg_wIIDgArltQ/NuImZor-pVg.jpg?size=300x450&quality=95&sign=4924c1e921fb943b08c9906b73f6d955&type=album', description: 'La trama gira en torno a Sophie, una muchacha de 18 años trabaja en la tienda de sombreros que le heredó su padre fallecido. Ella es solitaria y a quien le cuesta trabajo relacionarse. Su vida cambia cuando conoce al enigmático hechicero Howl, lo cual provoca los celos de la Bruja Calamidad, por lo que les lanza un hechizo que la transforma en una anciana de 80 años. Por esto, Sophie busca al Castillo Vagabundo, hogar del joven mago, para revertir el hechizo.', category: 'pelicula', tags: ['castillo', 'vagabundo', 'studio ghibli', 'animación', 'aventura', 'fantasía', 'romance'], author: 'Pelis182', duration: '119 min' },
  { id: 'chihiro-2001', title: 'El viaje de Chihiro (2001)', source: 'embed', url: 'https://barmonrey.com/player/VGmymjyIqYj6mLt/', thumbnail: 'https://sun9-8.userapi.com/impg/pIwsFG01-D--ZAG9WgtYGgouwpBVncfnF-PHqg/NVssIGJ_AkY.jpg?size=300x450&quality=95&sign=98d06ccbdd6b52b484f0bd768b7c5ddf&type=album', description: 'Chihiro es una niña de diez años que está mudándose con sus padres a un nuevo hogar. Por el camino, la familia se topa con un enorme edificio rojo en cuyo centro se abre un largo túnel. Al otro lado del pasadizo se dibuja una ciudad fantasma. En el restaurante abandonado de esta ciudad, los padres de Chihiro encuentran una gran variedad de platos deliciosos y deciden quedarse a comer, pero, al probar bocado, se transforman en cerdos. Presa del pánico, Chihiro huye y empieza a desmaterializarse poco a poco. El enigmático Haku le explicará el funcionamiento del universo en el que ha caído. Para salvar a sus padres, la niña tendrá que enfrentarse a la terrible Yubaba, que tiene el aspecto de una arpía diabólica.', category: 'pelicula', tags: ['chihiro', 'studio ghibli', 'animación', 'aventura', 'fantasía'], author: 'Pelis182', duration: '125 min' },
  { id: 'gran-hotel-budapest-2014', title: 'El gran hotel Budapest (2014)', source: 'embed', url: 'https://barmonrey.com/player/Z7jc3YK822K525i/', thumbnail: 'https://sun9-47.userapi.com/impg/IxxmufTF7Z5M6GlVqc-fYk_eqdtk-2gB68-U3A/QpKzUA9-Opg.jpg?size=300x450&quality=95&sign=f808354a06db71f78b1d6328ba4a92bf&type=album', description: 'Gustave trabaja como conserje en el famoso gran hotel Budapest. Allí entabla amistad con Zero Moustafa, el nuevo empleado que se convierte en su protegido y a quien explica todos los secretos de la profesión. De repente, la rica Madame D. muere y deja en herencia a Gustave un preciado cuadro del Renacimiento. Sin embargo, los herederos de la rica mujer no están de acuerdo con el testamento y acusan a Gustave de asesinato. Entonces el conserje deberá escapar de la policía con la ayuda de Zero.', category: 'pelicula', tags: ['hotel', 'budapest', 'comedia', 'drama'], author: 'Pelis182', duration: '99 min' },
  { id: 'perfume-2006', title: 'El perfume: Historia de un asesino (2006)', source: 'embed', url: 'https://barmonrey.com/player/kw0i3PhoiddJfzI/', thumbnail: 'https://pelis182.net/wp-content/uploads/2021/01/el-perfume.jpg', description: 'Francia, mediados del siglo XVIII. Jean Baptiste Grenouille es un joven que ha tenido una vida muy dura. Nacido entre los apestosos hedores de pescado podrido en un pequeño mercado, vio a una edad muy temprana cómo su madre le abandonaba en la basura. Poco después, gracias a la mediación de las autoridades, pasó por numeros hospicios donde su personalidad retraída le llevó a tener varios problemas; incluso sus compañeros le intentarón matarle aterrados por la gran diferencia que los separaba de ellos: Grenouille no olía a nada.', category: 'pelicula', tags: ['perfume', 'drama', 'fantasía', 'thriller'], author: 'Pelis182', duration: '147 min' },
  { id: 'hobbit-2012', title: 'El Hobbit: Un viaje inesperado (2012)', source: 'embed', url: 'https://barmonrey.com/player/vI1GXZb7Wo8304r/', thumbnail: 'https://pelis182.net/wp-content/uploads/2021/04/HOBBIT.jpg', description: 'Bilbo Bolsón es un apacible hobbit que habita en su cómoda casa en un lugar de La Comarca. Como a todos los hobbits, no le gusta salir de ahí y prefiere llevara una vida tranquilo. Un día toca a su puerta el mago Gandalf el Gris acompañado de trece enanos. Bilbo los recibe y en su casa y el mago lo invita a acompañarlos a una aventura sin igual: el grupo va en busca de la guarida de un dragón llamado Smaug que le robó todo su oro a los enanos. El hobbit opone resistencia, pero finalmente es persuadido por el mago para unírseles, sin saber que la decisión cambiará por siempre su existencia y también la de la Tierra Media.', category: 'pelicula', tags: ['hobbit', 'aventura', 'fantasía', 'fantasía'], author: 'Warner', duration: '169 min' },
  { id: 'hobbit-2013', title: 'El Hobbit: La desolación de Smaug (2013)', source: 'embed', url: 'https://barmonrey.com/player/mN3hvLgAvOO8ZKU/', thumbnail: 'https://sun9-55.userapi.com/impg/i0HVURogeDg-MRbJx62WkmgrT-itklLd2Q9n6w/lvzyuZHR8v0.jpg?size=300x450&quality=96&sign=3d95a06aa1f195c56453d32436b247e3&type=album', description: 'Luego de salir vivos de las peligrosas Montañas Nubladas el grupo liderado por el enano Thorin y del que forma parte Bilbo Bolsón. Separados de Gandalf el Gris, quien persuadió al pequeño hobbit para que los acompañara en la aventura, los trece enanos y Bilbo seguirán su camino con el fin de llegar a la guarida del dragón Smaug y recuperar los tesoros que este es robó. Pero los peligros abundan en el camino y los héroes tendrán que enfrentarse a arañas gigantes, orcos e incluso un grupo de elfos.', category: 'pelicula', tags: ['hobbit', 'aventura', 'fantasía'], author: 'Warner', duration: '186 min' },
  { id: 'hobbit-2014', title: 'El Hobbit: La batalla de los cinco ejércitos (2014)', source: 'embed', url: 'https://barmonrey.com/player/GifNT0aX1ouryP8/', thumbnail: 'https://sun9-53.userapi.com/impg/g28tF5SEHOuQWs2nAV6QCBk95qv8pBqbPHiloQ/qCgZIQ8i2gE.jpg?size=300x450&quality=96&sign=41462acb8fbd285313225a61b4f825f9&type=album', description: 'Después de enfrentarse al dragón Smaug, de recuperar el reino en la montaña y de encontrar el anillo que alguna vez estuvo en manos de Gollum, La Comunidad del Anillo ha desencadenado, sin quererlo, una fuerza maligna. El Smaug enfurecido vuela hacia la Ciudad del Lago para acabar con cualquier resto de vida, mientras Thorin, el rey enano, se vuelve codicioso con las enormes riquezas en su poder. Bilbo intenta hacerlo entrar en razón haciendo algo desesperado y peligroso. En el camino les esperan y ya no cuentan con la ayuda del mago Gandalf. El temible Sauron, su gran enemigo, se ha encargado de enviar legiones de orcos hacia la Montaña Solitaria para preparar un gran ataque.', category: 'pelicula', tags: ['hobbit', 'aventura', 'fantasía'], author: 'Warner', duration: '144 min' },
  { id: 'sr-nadie-2009', title: 'Sr. Nadie (2009)', source: 'embed', url: 'https://barmonrey.com/player/oHdkl1acXj1lyJt/', thumbnail: 'https://sun9-46.userapi.com/s/v1/ig2/tV3OS10V7S4FTQm9sQ-C4K9dez7OBLnegKtaFVuzjTw4SCl7PxjpAAZcxRyokeb9dmK9jhIks15LkyovjX83gmj1.jpg?quality=95&as=32x48,48x72,72x108,108x162,160x240,240x360,300x450&from=bu&cs=300x0', description: 'En el año 2092, la humanidad ha conquistado la inmortalidad a través de la renovación infinita de las células. El mundo observa fascinado cómo la vida de Nemo Nobody, el último mortal en la Tierra, de 118 años, se acerca a su fin. Para conocer detalles de la larga vida del protagonista, el doctor Feldheim, recurre a la hipnosis.', category: 'pelicula', tags: ['sr.nadie', 'ciencia ficción', 'drama', 'fantasía', 'romance'], author: 'Pelis182', duration: '141 min' },
  { id: 'cloud-atlas-2012', title: 'Cloud Atlas: La red invisible (2012)', source: 'embed', url: 'https://barmonrey.com/player/QpqEQTQghZUSJnG/', thumbnail: 'https://sun9-32.userapi.com/impg/V2wkWsiReV4rvo372jAaSVWcmzb8si72f3XJuA/zVzY-etAI3g.jpg?size=300x450&quality=95&sign=d87f16b2abff3cc014881f729c0acf27&type=album', description: 'Todo empieza en el siglo XIX. Un notario estadounidense llamado Adam Ewing regresa al lugar donde nació, California, después de haber viajado por las islas Ghatham. En su viaje, Ewing hace amistad con un médico que está tratándole contra una enfermedad contraída a través de un parásito.', category: 'pelicula', tags: ['cloud.atlas', 'ciencia ficción', 'drama', 'misterio'], author: 'Pelis182', duration: '172 min' },
  { id: 'outcome-2026', title: 'Outcome (2026)', source: 'embed', url: 'https://barmonrey.com/player/KjJKrduUyvntloT/', thumbnail: 'https://sun9-55.userapi.com/s/v1/ig2/3yPDEc5Ws5G8BuZwNRIT2Fwfs3nJ60aVoexlJE0ED7ww6fXc7zAvZF7tPLC1Ep6xipOldDH1w3GDl8QSod4M6NAt.jpg?quality=95', description: 'Reef Hawk, una adorada superestrella de Hollywood, cuya vida perfecta comienza a desmoronarse cuando recibe una amenaza anónima: un vídeo comprometedor que podría arruinar su reputación y poner fin a su carrera.', category: 'pelicula', tags: ['outcome', 'comedia', 'drama', 'misterio', 'thriller'], author: 'Pelis182', duration: '' },
  { id: 'nadie-2021', title: 'Nadie (2021)', source: 'embed', url: 'https://barmonrey.com/player/pEXqHcQ0P2dcmpX/', thumbnail: 'https://sun9-4.userapi.com/impg/Ci0HFoynneir7m09sjNHZj00dznkkdyG8yKmXw/qdf2hcAGAv0.jpg?size=300x450&quality=96&sign=75c8f2143418bd912bb5c87e552aac2e&type=album', description: 'Un hombre común, que ha decepcionado a su familia luego de no poder defenderlos en una noche de asalto, es empujado más allá de sus límites en Nadie.', category: 'pelicula', tags: ['nadie', 'acción', 'thriller'], author: 'Pelis182', duration: '92 min' },
  { id: 'nadie-2-2025', title: 'Nadie 2 (2025)', source: 'embed', url: 'https://barmonrey.com/player/e3RYjqcfbd0lVMM/', thumbnail: 'https://sun9-29.userapi.com/s/v1/ig2/OPMibftfXscNNYX29aQD2UVqZpdadbwIdFtq7Y1jQ4FXNub6KRmKy8u95wCRn8Ca7XgiwR8pCk_C7UxSVEKAtJz4.jpg?quality=95&as=32x48,48x72,72x108,108x162,160x240,240x360,300x450&from=bu&cs=300x0', description: 'Cuatro años después de enfrentarse involuntariamente a la mafia rusa, Hutch sigue manteniendo con la organización criminal una deuda de 30 millones de dólares que trata de saldar poco a poco con una serie interminable de golpes contra matones internacionales.', category: 'pelicula', tags: ['nadie2', 'acción', 'comedia', 'thriller'], author: 'Pelis182', duration: '' },
  { id: 'batman-azteca-2025', title: 'Batman Azteca: Choque de imperios (2025)', source: 'embed', url: 'https://barmonrey.com/player/35VxM76KAvnu4b9/', thumbnail: 'https://sun9-54.userapi.com/s/v1/ig2/cS-h2-GpLFfomlOTz-HnHaNY5--mSTt8f2suRjZ_K8uT56CFsMLSLrDwoyz3xkwTwrVEcE19ZhJ0oB4HdZ6RFOyu.jpg?quality=95', description: 'El padre de Yohualli Coatl, un joven azteca, es asesinado por los conquistadores españoles. Después de esto, advierte al rey Moctezuma del peligro y trabaja con los del templo de Tzinacan para desarrollar armamento y equipo para enfrentar a los invasores españoles.', category: 'pelicula', tags: ['batman', 'azteca', 'superhéroes', 'acción', 'animación', 'fantasía', 'ciencia ficción'], author: 'DC', duration: '' },
  { id: 'pelicula-intergalactico', title: 'GUÍA DEL VIAJERO INTERGALÁCTICO', source: 'youtube', url: 'https://drive.google.com/file/d/1OLjNKtj_oVH5m-a98NC833iwX2VRocAz/view', thumbnail: 'https://es.web.img3.acsta.net/pictures/npic/7.jpg', description: 'Guía del Viajero Intergaláctico - Película completa', category: 'pelicula', tags: ['pelicula', 'ciencia ficción', 'comedia'], author: 'Desconocido', duration: '' },
  { id: 'pelicula-adaline', title: 'EL SECRETO DE ADALINE', source: 'youtube', url: 'https://drive.google.com/file/d/0B95aowXSQsJ8OVhKbEV0dzFmUk0/view?resourcekey=0-fLr1pEFc7Wl894xVapGbtQ', thumbnail: 'https://es.web.img3.acsta.net/pictures/15/05/14/17/04/007466.jpg', description: 'EL SECRETO DE ADALINE - Película', category: 'pelicula', tags: [], author: 'Desconocido', duration: '112 min' },
  { id: 'lotr-fellowship-2001', title: 'El Señor de los Anillos: La Comunidad del Anillo (2001)', source: 'embed', url: 'https://barmonrey.com/player/m5rdLkcYQKbA4eV/', thumbnail: 'https://pelis182.net/wp-content/uploads/2020/09/ANILLO1.jpg', description: 'Se ha encontrado un antiguo anillo perdido durante siglos y a través de un extraño giro del destino, se le ha dado a un pequeño hobbit llamado Frodo. Cuando Gandalf descubre que el anillo es, de hecho, el anillo único del Señor Oscuro Sauron, ¡Frodo debe realizar una búsqueda épica en las Grietas del Destino para destruirlo! Sin embargo, él no se va sólo. Le acompañan Gandalf, Legolas el elfo, Gimli el enano, Aragorn, Boromir y sus tres amigos hobbits: Merry, Pippin y Samwise. La Comunidad del Anillo debe ir através de las montañas, la nieve, la oscuridad, los bosques, los ríos y las llanuras, enfrentando el mal y el peligro en cada esquina.', category: 'pelicula', tags: ['senor de los anillos', 'comunidad del anillo', 'fantasía', 'aventura', 'drama'], author: 'Warner', duration: '178 min' },
  { id: 'lotr-towers-2002', title: 'El Señor de los Anillos: Las dos torres (2002)', source: 'embed', url: 'https://barmonrey.com/player/5AODAbKZxFuynUI/', thumbnail: 'https://pelis182.net/wp-content/uploads/2020/09/ANILLO2.jpg', description: 'En la búsqueda para destruir el Anillo Único, la comunidad ha quedado disuelta. Frodo y Sam descubren que están siendo seguidos por el misterioso Gollum. Mientras Frodo y Sam se acercan más a Mordor con la ayuda del furtivo Gollum, la comunidad dividida se enfrenta al nuevo aliado de Sauron: Saruman y sus hordas de Isengard. Aragorn, el arquero elfo Legolas y Gimli el Enano se encuentran con el asediado reino de Rohan, cuyo alguna vez gran Rey Théoden cayó bajo el hechizo mortal de Saruman. Mientras tanto, los hobbits Merry y Pippin, que estaban prisioneros de los Uruk-hai, han escapado y descubren en el misterioso Bosque de Fangorn a un aliado inesperado: Bárbol, guardián de los árboles y representante de un antiguo pueblo vegetal que Saruman había diezmado.', category: 'pelicula', tags: ['senor de los anillos', 'dos torres', 'fantasía', 'aventura', 'drama'], author: 'Warner', duration: '179 min' },
  { id: 'lotr-return-king-2003', title: 'El Señor de los Anillos: El retorno del Rey (2003)', source: 'embed', url: 'https://barmonrey.com/player/ad1S0YNfNqBpPGM/', thumbnail: 'https://pelis182.net/wp-content/uploads/2020/09/ANILLO3.jpg', description: 'El ejército de Sauron ha atacado Minas Tirith, la capital de Gondor. Una poderosa amenaza pone en peligro la paz del reino, antaño poderoso y que ahora necesita más que nunca a su rey. Ante esta situación límite, Aragorn se presenta como una figura clave para llevar al reino a la victoria pero, ¿será capaz de cumplir con su destino? Mientras tanto, Gandalf intentará contener a las fuerzas destructoras de Gondor y Théoden pediría a los guerreros de Rohan que se unan al combate. Sin embargo, a pesar de su valor y lealtad, parece que las fuerzas de los Hombres no serán suficientes para derrotar a las inconmensurables legiones de ennemis que se ciernen sobre el reino.', category: 'pelicula', tags: ['senor de los anillos', 'retorno del rey', 'fantasía', 'aventura', 'drama'], author: 'Warner', duration: '201 min' },
  { id: 'lotr-rohirrim-2024', title: 'El Señor de los Anillos: La guerra de los Rohirrim (2024)', source: 'embed', url: 'https://barmonrey.com/player/aIPnuAfPhUSrYmE/', thumbnail: 'https://pelis182.net/wp-content/uploads/2024/12/1366_2000.jpeg', description: 'Ambientada 183 años antes de los acontecimientos de la trilogía original de películas, El Señor de los Anillos: La guerra de los Rohirrim narra el destino de la Casa de Helm Hammerhand, el legendario Rey de Rohan. Un repentino ataque de Wulf, un astuto y despiadado señor de los Dunlending que busca venganza por la muerte de su padre, obliga a Helm y a su pueblo a hacer una última y audaz resistencia en el antiguo bastión del Hornburg, una poderosa fortaleza que más tarde será conocida como el Abismo de Helm. Encontrándose en una situación cada vez más desesperada, Héra, la hija de Helm, debe reunir la voluntad para liderar la resistencia contra un enemigo mortal que pretende su destrucción total.', category: 'pelicula', tags: ['senor de los anillos', 'guerra de los rohirrim', 'animación', 'fantasía', 'aventura', 'drama'], author: 'Warner', duration: '134 min' },
];

